@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_loading)
    {
        <div class="product-search__status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search__error">
            <span>Search failed: @_error</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_results is not null && _results.Count == 0)
    {
        <div class="product-search__status">No products found.</div>
    }

    @if (_results is { Count: > 0 })
    {
        <div class="product-search__grid">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => OnProductSelected.InvokeAsync(product)">
                    <img class="product-card__image" src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                    <div class="product-card__name">@product.Name</div>
                    <div class="product-card__price">@product.Price.ToString("C")</div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product>? _results;
    private bool _loading;
    private string? _error;

    private Timer? _debounceTimer;
    private CancellationTokenSource? _searchCts;
    private bool _disposed;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any in-flight search immediately so the old request is abandoned.
        CancelPendingSearch();

        // Reset (or restart) the 300 ms debounce timer.
        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(OnDebounceElapsed, _query, 300, Timeout.Infinite);
    }

    private async void OnDebounceElapsed(object? state)
    {
        var query = (string)state!;
        await InvokeAsync(() => ExecuteSearchAsync(query));
    }

    private async Task ExecuteSearchAsync(string query)
    {
        if (string.IsNullOrWhiteSpace(query))
        {
            _results = null;
            _error = null;
            _loading = false;
            StateHasChanged();
            return;
        }

        _loading = true;
        _error = null;
        StateHasChanged();

        var cts = new CancellationTokenSource();
        _searchCts = cts;

        try
        {
            var results = await ProductService.SearchAsync(query, cts.Token);

            // Only apply results if this CTS is still the active one
            // (i.e. no newer search has replaced it).
            if (!cts.Token.IsCancellationRequested)
            {
                _results = results;
                _error = null;
            }
        }
        catch (OperationCanceledException)
        {
            // Search was superseded by a newer query — nothing to do.
        }
        catch (Exception ex)
        {
            if (!cts.Token.IsCancellationRequested)
            {
                _error = ex.Message;
                _results = null;
            }
        }
        finally
        {
            if (ReferenceEquals(_searchCts, cts))
            {
                _loading = false;
            }

            cts.Dispose();
            StateHasChanged();
        }
    }

    private void RetrySearch() => _ = ExecuteSearchAsync(_query);

    private void CancelPendingSearch()
    {
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = null;
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        _debounceTimer?.Dispose();
        CancelPendingSearch();
    }
}

